mapper.insert:
/*Reply - replyInsert*/
select flea_reply_seq.nextval from dual
INSERT INTO fleaReply(fleaReply_no, flea_no, fleaReply_content, fleaReply_date, user_id, user_name) VALUES(#{fleaReply_no},#{flea_no},#{fleaReply_content}, sysdate, #{user_id},#{user_name})

mapper.update:
UPDATE fleaReply
SET fleaReply_content = #{fleaReply_content}, fleaReply_date = sysdate
WHERE fleaReply_no = #{fleaReply_no}

mapper.select:
SELECT flea_no
FROM fleaReply
WHERE fleaReply_no = #{fleaReply_no}
